import { Router } from "express";
import { createTransaction, getMyTransactions, payTransaction, getMyPoints, } from "../controllers/transaction.controller.js";
import { authMiddleware } from "../middlewares/auth.middleware.js";
const router = Router();
router.use(authMiddleware);
router.post("/", createTransaction);
router.get("/me", getMyTransactions);
router.get("/points", getMyPoints);
router.patch("/:id/pay", payTransaction);
export default router;
